content:
{
  "schemaVersion": 3,
  "judgeId": "judge_2",
  "batchIndex": 0,
  "comparisons": [
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c2_bamboo_traps",
      "winnerId": "c1_bycatch_ice",
      "reason": "Cả hai đều có cơ chế tốt, nhưng c1 bám sát yêu cầu về việc nhận diện sản lượng bị đánh giá thấp (cá dạt) và giải quyết bài toán bảo quản bằng vật liệu thô sơ (bèo tây) rất đặc trưng cho bối cảnh Việt Nam cuối thập niên 80. c2 tập trung vào đánh bắt, nhưng c1 có chiều sâu hơn về chuỗi cung ứng và tối ưu hóa giá trị."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c3_sun_drying_fish",
      "winnerId": "c1_bycatch_ice",
      "reason": "c1 thắng nhờ cơ chế bảo quản tươi bằng cách nhiệt tự nhiên, tạo ra sự chủ động cao hơn trong việc chạy đua với thời gian lên chợ huyện. c3 dựa nhiều vào thời tiết (nắng), rủi ro hỏng mẻ hàng do mưa rào ở chương 3 khiến nhịp độ có thể bị kéo chậm hơn so với sự 'khoái hoạt' của c1."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c4_rock_pool_tides",
      "winnerId": "c1_bycatch_ice",
      "reason": "c4 có yếu tố mạo hiểm cao nhưng cơ chế 'nhặt lộc' mang tính khai thác tài nguyên sẵn có hơn là 'làm giàu bằng tay nghề' và tối ưu hóa như c1. c1 thể hiện rõ quá trình thị trường hóa ban đầu thông qua việc phân loại và bảo quản cá dạt để bán giá cá tươi."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c5_shrimp_paste",
      "winnerId": "c1_bycatch_ice",
      "reason": "c5 có vòng lặp thưởng tốt (10 ngày), nhưng c1 tạo ra thành quả ngay lập tức ở chương 3 (tiền tươi thóc thật từ mẻ cá dạt) và giải quyết được vấn đề nhức nhối của ngư dân thời đó là thiếu đá lạnh bằng một giải pháp dân gian sáng tạo."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c6_handline_bait",
      "winnerId": "c1_bycatch_ice",
      "reason": "c6 hơi hướng 'bàn tay vàng' với kỹ năng cảm nhận rung động và mồi bí truyền. c1 thực tế hơn khi tập trung vào việc xử lý hao hụt - một vấn đề kinh tế thực sự của ngành biển thập niên 80. Đối thủ của c1 (trưởng bến cá) cũng thực tế và có lợi ích riêng hơn."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c7_live_seafood_transport",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 vượt trội nhờ cơ chế cơ khí ứng dụng (bơm xe đạp làm sục khí) cực kỳ sáng tạo và đậm chất Việt Nam thời kỳ thiếu thốn. Hình ảnh nhân vật vừa đạp xe vừa bơm oxy tạo ra 'causal cost' và agency rất mạnh mẽ, khớp hoàn hảo với yêu cầu về dụng cụ có nguồn gốc rõ ràng."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c8_light_luring_squid",
      "winnerId": "c1_bycatch_ice",
      "reason": "c8 tập trung vào cải tiến đèn măng xông, nhưng rủi ro về chi phí dầu hỏa và vỡ kính đèn khiến mô hình này dễ rơi vào bế tắc nếu không có vốn lớn. c1 dùng bèo tây (miễn phí) để tạo giá trị gia tăng, thể hiện sự nhạy bén của một người từng trải tốt hơn."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c9_oyster_spat_poles",
      "winnerId": "c1_bycatch_ice",
      "reason": "c9 là mô hình nuôi trồng dài hạn, khó đạt được yêu cầu 'chậm nhất chương 3 phải có tiền/bữa cơm tốt hơn' một cách thuyết phục như c1. c1 giải quyết nhu cầu thực phẩm và tiền bạc ngay lập tức thông qua việc cứu mẻ cá sắp hỏng."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "c10_net_modifications",
      "winnerId": "c1_bycatch_ice",
      "reason": "c10 là mô hình dịch vụ (vá lưới), phụ thuộc vào việc chủ tàu có tin tưởng hay không. c1 chủ động hoàn toàn từ khâu thu mua, xử lý đến bán hàng, tạo ra cảm giác 'làm chủ vận mệnh' mạnh hơn cho độc giả nam tần."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_01",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 01 tập trung vào nấu nướng (phụ phẩm), trong khi c1 tập trung vào thương mại hải sản và logistics thô sơ. c1 khớp hơn với domain opportunity về 'đánh bắt, phân loại, đá lạnh và muối' của một huyện biển."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_02",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 02 dùng kiến thức vi sinh hiện đại để cứu mắm, hơi lệch tông so với yêu cầu 'không áp kỹ thuật hiện đại vượt điều kiện cuối thập niên 80'. c1 dùng bèo tây và lá chuối là những vật liệu hoàn toàn tự nhiên và sẵn có tại chỗ."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_03",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 03 tương tự c10, tập trung vào sửa chữa. c1 có vòng lặp kinh tế rõ ràng hơn: mua rẻ - bảo quản - bán đắt - tái đầu tư, phù hợp với nhịp đọc 'làm giàu từng bước'."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_04",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 04 về rong biển có rào cản thị trường rất lớn (người dân coi là rác). c1 kinh doanh cá - mặt hàng thiết yếu, nên việc 'biến hiểu biết thành mẻ hàng' diễn ra mượt mà và thuyết phục hơn trong 3 chương đầu."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_05",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 05 tập trung vào xây hầm đá, nhưng c1 có thêm yếu tố 'cá dạt' (bycatch) - một loại sản lượng bị đánh giá thấp, giúp kích hoạt cơ chế 'nhận ra mùa vụ/loại hải sản' tốt hơn theo yêu cầu commission."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_06",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 06 về thiết kế tàu thuyền quá thiên về kỹ thuật và cần thời gian thi công dài. c1 mang lại thành quả sớm (bữa cơm có thịt ở chương 3) đúng với mong đợi của độc giả Việt."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_07",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 07 về ruốc sấy khá tốt nhưng c1 có sự đối đầu trực tiếp với nắng gắt và thời gian bảo quản tươi, tạo ra áp lực (tension) tốt hơn cho hành động của nhân vật chính."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_08",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 08 dựa vào việc tìm bãi sò mới, dễ bị sa vào mô hình 'may mắn/kho báu'. c1 dựa trên việc tối ưu hóa những gì người khác bỏ đi ngay tại bến cá, thể hiện năng lực 'người từng trải' rõ rệt hơn."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_09",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 09 về phân loại muối hơi tĩnh lặng. c1 có sự năng động của bến cá, chợ huyện và việc vận chuyển, tạo ra không khí 'thị trường hóa ban đầu' sôi động hơn."
    },
    {
      "leftId": "c1_bycatch_ice",
      "rightId": "dt_01_concept_10",
      "winnerId": "c1_bycatch_ice",
      "reason": "Concept 10 về du lịch hoàn toàn không phù hợp với bối cảnh kinh tế Việt Nam năm 1988 (vừa xóa bỏ bao cấp, dân còn đói). c1 thực tế và bám sát sinh kế người dân hơn."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "c3_sun_drying_fish",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 thắng nhờ cơ chế 'đọc con nước' và kỹ thuật đan lồng bẫy thủ công tạo ra sản phẩm giá trị cao (ghẹ sống). c3 phụ thuộc quá nhiều vào nắng, nếu không có nắng thì cơ chế bị gãy, trong khi c2 thể hiện sự chủ động tìm tòi nguồn lợi ở rạn đá ngầm."
    }
  ]
}
